// Function to calculate GPA
double calculateGPA(const std::vector<double>& grades) {
    double total = 0.0;
    int count = 0;
    for (double grade : grades) {
        if (grade >= 0 && grade <= 4.0) {
            total += grade;
            count++;
        }
    }
    return count > 0 ? total / count : 0.0;
}
